Here's a complete implementation:

**XAML — `ItemsPage.xaml`**

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:models="clr-namespace:MyApp.Models"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">
        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">
            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                        <VisualStateManager.VisualStateGroups>
                            <VisualStateGroup Name="CommonStates">
                                <VisualState Name="Normal">
                                    <VisualState.Setters>
                                        <Setter Property="BackgroundColor" Value="Transparent" />
                                    </VisualState.Setters>
                                </VisualState>
                                <VisualState Name="Selected">
                                    <VisualState.Setters>
                                        <Setter Property="BackgroundColor" Value="{StaticResource Primary}" />
                                    </VisualState.Setters>
                                </VisualState>
                            </VisualStateGroup>
                        </VisualStateManager.VisualStateGroups>
                        <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                        <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>
            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center" VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>
        </CollectionView>
    </RefreshView>
</ContentPage>
```

**ViewModel — `ItemsViewModel.cs`**

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private ObservableCollection<Item> _items = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task Refresh()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in data)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false; // Must set false to hide spinner
        }
    }

    [RelayCommand]
    private async Task ItemSelected()
    {
        if (CurrentItem is null) return;

        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            { "Item", CurrentItem }
        });

        CurrentItem = null; // Reset so the same item can be re-selected
    }
}
```

**Key bindings explained:**

| Property | Purpose |
|---|---|
| `RefreshView.IsRefreshing` → `IsRefreshing` | Two-way; controls the spinner. **You must set it `false`** when done. |
| `RefreshView.Command` → `RefreshCommand` | Fires on pull-down; calls your API. |
| `SelectionMode="Single"` | Enables single-tap selection. |
| `SelectedItem` → `CurrentItem` (TwoWay) | Tracks the tapped item. Reset to `null` after navigation so the same item can be re-selected. |
| `SelectionChangedCommand` → `ItemSelectedCommand` | Fires on selection change; triggers navigation. |
| `ItemsSource` → `Items` (`ObservableCollection<T>`) | **Must** be `ObservableCollection`, not `List`, so add/remove updates the UI automatically. |

**Important rules:**
- Always update the collection on the **UI thread** (`MainThread.BeginInvokeOnMainThread`).
- Never use `ViewCell` — use `Grid`, `StackLayout`, or any `View` as the template root.
- Set `x:DataType` on every `DataTemplate` for compiled bindings.
